#include <stdio.h>

void priorityEncoder(int input[]) {
    // input[0] = I0 (lowest), input[7] = I7 (highest)
    // Output: Y2Y1Y0
    int y0 = 0, y1 = 0, y2 = 0, v = 0;

    if (input[7]) { y2=1; y1=1; y0=1; v=1; }
    else if (input[6]) { y2=1; y1=1; y0=0; v=1; }
    else if (input[5]) { y2=1; y1=0; y0=1; v=1; }
    else if (input[4]) { y2=1; y1=0; y0=0; v=1; }
    else if (input[3]) { y2=0; y1=1; y0=1; v=1; }
    else if (input[2]) { y2=0; y1=1; y0=0; v=1; }
    else if (input[1]) { y2=0; y1=0; y0=1; v=1; }
    else if (input[0]) { y2=0; y1=0; y0=0; v=1; }
    else { v = 0; }

    printf("Output: Y2=%d Y1=%d Y0=%d Valid=%d\n", y2, y1, y0, v);
}

int main() {
    int inputs[8] = {0, 0, 0, 0, 0, 1, 0, 0};  // I5 = 1
    priorityEncoder(inputs);  // Output: 101 (5)
    return 0;
}

public class DecimalToBCD {
    // 10 inputs (keys 0-9), 4 BCD outputs
    public static int[] decimalToBCD(int[] decimalInput) {
        // decimalInput[0] = key 0 pressed, etc.
        // Returns 4-bit BCD output
        int[] bcd = {0, 0, 0, 0};  // D, C, B, A (MSB to LSB)

        // D output (MSB) = OR of inputs 8, 9
        bcd[0] = decimalInput[8] | decimalInput[9];

        // C output = OR of inputs 4, 5, 6, 7
        bcd[1] = decimalInput[4] | decimalInput[5] | decimalInput[6] | decimalInput[7];

        // B output = OR of inputs 2, 3, 6, 7, 8, 9
        bcd[2] = decimalInput[2] | decimalInput[3] | decimalInput[6] | decimalInput[7] | decimalInput[8] | decimalInput[9];

        // A output (LSB) = OR of inputs 1, 3, 5, 7, 9
        bcd[3] = decimalInput[1] | decimalInput[3] | decimalInput[5] | decimalInput[7] | decimalInput[9];

        return bcd;
    }

    public static void main(String[] args) {
        int[] input = new int[10];
        input[5] = 1;  // Press key 5

        int[] bcd = decimalToBCD(input);
        System.out.print("BCD Output: ");
        for (int bit : bcd) System.out.print(bit);
        // Outputs: 0101 (BCD for 5)
    }
}
